namespace schema_manage_indexes {

  struct Product {
    sqlgen::PrimaryKey<int> product_id;
    std::string sku;
    std::string name;
    std::string category;
    double price;
  };

  bool manage_indexes() {
    // Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = *conn_result;

    using namespace sqlgen::literals;

    // Create standard index on category with IF NOT EXISTS
    auto idx_category = sqlgen::create_index<"idx_product_category", Product>("category"_c);
    idx_category.if_not_exists_ = true;

    // Create unique index on sku with IF NOT EXISTS
    auto idx_sku = sqlgen::create_index<"idx_product_sku", Product>("sku"_c);
    idx_sku.unique_ = true;
    idx_sku.if_not_exists_ = true;

    // Create composite index on (name, price) with IF NOT EXISTS
    auto idx_name_price = sqlgen::create_index<"idx_product_name_price", Product>("name"_c, "price"_c);
    idx_name_price.if_not_exists_ = true;

    // Convert to SQL and execute each index creation
    auto execute_index = [&](const auto& index) -> bool {
      auto stmt = sqlgen::transpilation::to_sql(index);
      auto sql = conn->to_sql(stmt);
      auto res = conn->execute(sql);
      return res ? true : false;
    };

    return execute_index(idx_category) && execute_index(idx_sku) && execute_index(idx_name_price);
  }

}  // namespace schema_manage_indexes
```

