namespace analyze_social_network {

struct User {
    sqlgen::PrimaryKey<int> user_id;
    std::string username;
    std::string email;
    sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
    std::string city;
};

struct Friendship {
    int user_id1;
    int user_id2;
    sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
};

struct FriendConnection {
    std::string user1_name;
    std::string user2_name;
};

struct MutualFriend {
    std::string user1;
    std::string user2;
    int mutual_count;
};

struct FriendStats {
    int user_id;
    std::string username;
    int friend_count;
};

struct FriendOfFriend {
    std::string user1;
    std::string user2;
    std::string common_friend;
};

struct SameCityRecommendation {
    std::string user1;
    std::string user2;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen::literals;

    // Connect to in-memory SQLite database
    auto conn = sqlgen::sqlite::connect(":memory:");

    // Create tables
    auto create_user_table = sqlgen::create_table<User>;
    auto create_friendship_table = sqlgen::create_table<Friendship>;

    // Insert data
    auto insert_users = sqlgen::write(users);
    auto insert_friendships = sqlgen::write(friendships);

    // 1. Find mutual friends using SELF-JOIN
    auto mutual_query = sqlgen::select_from<User, "u1">("username"_t1, "username"_t2)
        | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
        | sqlgen::inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
        | sqlgen::inner_join<User, "u2">("user_id2"_t2 == "user_id"_t2)
        | sqlgen::where("user_id"_t1 < "user_id"_t2)
        | sqlgen::group_by("user_id"_t1, "user_id"_t2)
        | sqlgen::having(sqlgen::count() > 0);

    auto mutual_result = mutual_query(conn);

    // 2. Find users with more than average friends using nested query
    auto avg_query = sqlgen::select_from<User, "u">(sqlgen::count().as<"friend_count">)
        | sqlgen::left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t2)
        | sqlgen::group_by("user_id"_t1);

    auto user_stats_query = sqlgen::select_from<User, "u">(sqlgen::count().as<"friend_count">)
        | sqlgen::left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t2)
        | sqlgen::group_by("user_id"_t1)
        | sqlgen::having(sqlgen::count() > (avg_query | sqlgen::to<int>)(conn));

    auto user_stats_result = user_stats_query(conn);

    // 3. Find friend-of-friend relationships
    auto friend_of_friend_query = sqlgen::select_from<User, "u1">("username"_t1, "username"_t2)
        | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
        | sqlgen::inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
        | sqlgen::inner_join<User, "u2">("user_id2"_t2 == "user_id"_t2)
        | sqlgen::where(sqlgen::count_distinct("user_id2"_t1) == 1);

    auto friend_of_friend_result = friend_of_friend_query(conn);

    // 4. Count friends per user and find most connected users
    auto friend_count_query = sqlgen::select_from<User, "u">(sqlgen::count().as<"friend_count">)
        | sqlgen::left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t2)
        | sqlgen::group_by("user_id"_t1)
        | sqlgen::order_by(sqlgen::count().desc());

    auto friend_count_result = friend_count_query(conn);

    // 5. Find same-city recommendations
    auto recommendation_query = sqlgen::select_from<User, "u1">("username"_t1, "username"_t2)
        | sqlgen::inner_join<User, "u2">("city"_t1 == "city"_t2)
        | sqlgen::where("user_id"_t1 < "user_id"_t2)
        | sqlgen::where(!sqlgen::exists(
            sqlgen::select_from<Friendship, "f">(sqlgen::literal(1))
            | sqlgen::where(("user_id1"_t3 == "user_id"_t1) && ("user_id2"_t3 == "user_id"_t2))
        ));

    auto recommendation_result = recommendation_query(conn);

    // Process results and return FriendConnection objects
    std::vector<FriendConnection> results;

    // Add mutual friends results
    for (const auto& row : mutual_result) {
        results.emplace_back(FriendConnection{
            .user1_name = row.user1_name,
            .user2_name = row.user2_name
        });
    }

    // Add friend-of-friend results
    for (const auto& row : friend_of_friend_result) {
        results.emplace_back(FriendConnection{
            .user1_name = row.user1_name,
            .user2_name = row.user2_name
        });
    }

    // Add recommendation results
    for (const auto& row : recommendation_result) {
        results.emplace_back(FriendConnection{
            .user1_name = row.user1_name,
            .user2_name = row.user2_name
        });
    }

    return results;
}

}  // namespace analyze_social_network
```

