  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // 2. Create the Account table using write with an empty vector
  std::vector<Account> empty_accounts;
  auto create_table_result = sqlgen::write(conn, empty_accounts);
  if (!create_table_result) {
    return false;
  }

  // 3. Update balances and statuses using set operations
  // Update account_id=1: set balance to 1000.0 and status to "active"
  auto update1 = sqlgen::update<Account>(
      "balance"_c.set(1000.0),
      "status"_c.set("active")
  ).where("account_id"_c == 1);

  // Update account_id=2: set balance to 2000.0 and status to "inactive"
  auto update2 = sqlgen::update<Account>(
      "balance"_c.set(2000.0),
      "status"_c.set("inactive")
  ).where("account_id"_c == 2);

  // 4. Execute the updates
  auto update1_result = update1(conn);
  if (!update1_result) {
    return false;
  }

  auto update2_result = update2(conn);
  if (!update2_result) {
    return false;
  }

  // 5. Verify changes persisted by reading the data back
  auto read_result = sqlgen::read<std::vector<Account>>(conn);
  if (!read_result) {
    return false;
  }

  auto accounts = read_result.value();

  // Verify account_id=1 has correct values
  bool found_account1 = false;
  for (const auto& account : accounts) {
    if (account.account_id == 1) {
      found_account1 = true;
      if (account.balance != 1000.0 || account.status != "active") {
        return false;
      }
    }
    if (account.account_id == 2) {
      if (account.balance != 2000.0 || account.status != "inactive") {
        return false;
      }
    }
  }

  if (!found_account1) {
    return false;
  }

  return true;
}

}  // namespace update_set_operations

