Based on the reference materials and detailed specifications, here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen::literals;

    // Create SELECT query from Source table
    auto select_query = sqlgen::select_from<Source>("value"_c);

    // Apply WHERE condition (value > 100)
    auto filtered_query = select_query | sqlgen::where("value"_c > 100);

    // Create CREATE TABLE AS statement for Target table
    return sqlgen::create_as<Target>(filtered_query);
}

}  // namespace create_table_as_select
```

## Explanation:

1. **`sqlgen::select_from<Source>("value"_c)`**: Creates a SELECT query from the `Source` table, selecting only the `value` column using the column literal `"value"_c`.

2. **`| sqlgen::where("value"_c > 100)`**: Applies the WHERE condition using the pipe operator `|` to filter records where `value > 100`.

3. **`sqlgen::create_as<Target>(filtered_query)`**: Creates a CREATE TABLE AS statement that will create the `Target` table from the filtered SELECT query.

The function returns the query object, which can be executed against a database connection to create the table with the specified structure and data.

